import{_ as t,o as a,c as r,a2 as n}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Ante — References & Links","description":"","frontmatter":{"title":"Ante — References & Links","status":"complete"},"headers":[],"relativePath":"research/agents/ante/references.md","filePath":"research/agents/ante/references.md"}'),o={name:"research/agents/ante/references.md"};function i(s,e,l,c,g,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="ante-—-references-links" tabindex="-1">Ante — References &amp; Links <a class="header-anchor" href="#ante-—-references-links" aria-label="Permalink to &quot;Ante — References &amp; Links&quot;">​</a></h1><blockquote><p>Curated collection of references, links, and resources related to <strong>Ante</strong> by Antigma Labs — a terminal-native AI coding agent built in Rust. This page covers official channels, source code, publications, benchmark results, and the broader ecosystem that informs Ante&#39;s design.</p></blockquote><hr><h2 id="official-resources" tabindex="-1">Official Resources <a class="header-anchor" href="#official-resources" aria-label="Permalink to &quot;Official Resources&quot;">​</a></h2><ul><li><p><strong>Website</strong> — <a href="https://antigma.ai" target="_blank" rel="noreferrer">antigma.ai</a> Product homepage for Antigma Labs; includes blog, documentation links, and company information.</p></li><li><p><strong>Documentation</strong> — <a href="https://docs.antigma.ai" target="_blank" rel="noreferrer">docs.antigma.ai</a> Technical documentation for Ante and related tooling. Access-restricted; may require an account or invitation.</p></li><li><p><strong>Discord</strong> — <a href="https://discord.gg/pqhj3DNGz2" target="_blank" rel="noreferrer">discord.gg/pqhj3DNGz2</a> · <a href="https://discord.gg/yvgypZ6B" target="_blank" rel="noreferrer">discord.gg/yvgypZ6B</a> Community server for discussion, support, and announcements. Two invite links circulate; both lead to the same server.</p></li><li><p><strong>Twitter / X</strong> — <a href="https://x.com/antigma_labs" target="_blank" rel="noreferrer">@antigma_labs</a> Official account for product updates, benchmark results, and blog post announcements.</p></li><li><p><strong>Hugging Face</strong> — <a href="https://huggingface.co/Antigma" target="_blank" rel="noreferrer">huggingface.co/Antigma</a> Organization page hosting models, datasets, and interactive spaces (e.g., Abliteration demo).</p></li><li><p><strong>Contact</strong> — <a href="mailto:contact@antigma.ai" target="_blank" rel="noreferrer">contact@antigma.ai</a></p></li></ul><hr><h2 id="github-repositories" tabindex="-1">GitHub Repositories <a class="header-anchor" href="#github-repositories" aria-label="Permalink to &quot;GitHub Repositories&quot;">​</a></h2><ul><li><p><strong>Organization</strong> — <a href="https://github.com/AntigmaLabs" target="_blank" rel="noreferrer">github.com/AntigmaLabs</a></p></li><li><p><strong><code>mcp-sdk</code></strong> (64 ⭐) — <a href="https://github.com/AntigmaLabs/mcp-sdk" target="_blank" rel="noreferrer">github.com/AntigmaLabs/mcp-sdk</a> Minimalistic Rust implementation of the Model Context Protocol (MCP). Provides the protocol layer Ante uses to communicate with LLM providers and tool servers.</p><ul><li>Crates.io package: <a href="https://crates.io/crates/mcp-sdk" target="_blank" rel="noreferrer">crates.io/crates/mcp-sdk</a></li></ul></li><li><p><strong><code>nanochat-rs</code></strong> (62 ⭐) — <a href="https://github.com/AntigmaLabs/nanochat-rs" target="_blank" rel="noreferrer">github.com/AntigmaLabs/nanochat-rs</a> Tiny cognitive core built with native Rust, inspired by <a href="https://github.com/karpathy/nanochat" target="_blank" rel="noreferrer">nanochat</a> from Andrej Karpathy. Demonstrates local inference without Python dependencies, using the HuggingFace Candle tensor library.</p><ul><li>Model weights: <a href="https://huggingface.co/Antigma/nanochat-d32" target="_blank" rel="noreferrer">huggingface.co/Antigma/nanochat-d32</a></li></ul></li></ul><hr><h2 id="blog-posts" tabindex="-1">Blog Posts <a class="header-anchor" href="#blog-posts" aria-label="Permalink to &quot;Blog Posts&quot;">​</a></h2><ul><li><p><strong>&quot;How to Achieve #1 on Terminal Bench&quot;</strong> — Mar 13, 2026 · 13 min read <a href="https://antigma.ai/blog/2026/03/13/terminal-bench" target="_blank" rel="noreferrer">antigma.ai/blog/2026/03/13/terminal-bench</a> Forensic analysis of benchmark manipulation on Terminal Bench 2.0. Exposes how rankings can be gamed, and discusses the implications for evaluating coding agents honestly.</p></li><li><p><strong>&quot;Abliteration: Declaration of Independence from Excessive Model Restriction&quot;</strong> — Jul 1, 2025 · 5 min read <a href="https://antigma.ai/blog/2025/07/01/Abliteration" target="_blank" rel="noreferrer">antigma.ai/blog/2025/07/01/Abliteration</a> Describes a technique for relaxing overly aggressive moderation guardrails in open-source LLMs without full fine-tuning. Builds on research from the <code>remove-refusals-with-transformers</code> project.</p><ul><li>Interactive demo: <a href="https://huggingface.co/spaces/Antigma/Abliteration" target="_blank" rel="noreferrer">huggingface.co/spaces/Antigma/Abliteration</a></li></ul></li><li><p><strong>&quot;Neural Cellular Automata (NCA) — Interactive Demo&quot;</strong> — Jun 29, 2025 · 13 min read <a href="https://antigma.ai/blog/2025/06/29/NCA" target="_blank" rel="noreferrer">antigma.ai/blog/2025/06/29/NCA</a> Exploration of self-organizing neural systems with a browser-based interactive demo.</p></li><li><p><strong>&quot;Sovereign Compute and Network State&quot;</strong> — Jan 22, 2025 · 4 min read <a href="https://antigma.ai/blog/2025/01/22/network-state/vision" target="_blank" rel="noreferrer">antigma.ai/blog/2025/01/22/network-state/vision</a> Articulates a vision for privacy, trust, and the &quot;right to bear arms&quot; in AI — arguing that access to powerful models is a fundamental right, not a privilege to be gatekept.</p></li><li><p><strong>&quot;The Crypto Way&quot;</strong> — Aug 3, 2024 · 2 min read <a href="https://antigma.ai/blog/2024/08/03/crypto/the_crypto_way" target="_blank" rel="noreferrer">antigma.ai/blog/2024/08/03/crypto/the_crypto_way</a> Short essay on cryptographic principles as a philosophical foundation for decentralized AI infrastructure.</p></li><li><p><strong>&quot;Antigma Manifesto&quot;</strong> — Jul 17, 2024 · 2 min read <a href="https://antigma.ai/blog/2024/07/17/manifesto" target="_blank" rel="noreferrer">antigma.ai/blog/2024/07/17/manifesto</a> Founding mission statement for Antigma Labs. Outlines the three pillars of the company and the origin of the name (anti-Enigma → Antigma, a nod to Turing and Bletchley Park).</p></li></ul><hr><h2 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks&quot;">​</a></h2><ul><li><p><strong>Terminal-Bench 2.0</strong> — Rank <strong>#17</strong> (Ante + Gemini 3 Pro, score 69.4%) Second-generation terminal agent benchmark measuring real-world coding task completion.</p></li><li><p><strong>Terminal-Bench 1.0</strong> — Rank <strong>#4</strong> (Ante + claude-sonnet-4-5, score 60.3%) First-generation benchmark; Ante&#39;s strong placement here preceded the team&#39;s investigation into benchmark integrity, which led to the &quot;How to Achieve #1 on Terminal Bench&quot; blog post.</p></li><li><p><strong>Terminal-Bench website</strong> — <a href="https://terminal-bench.com" target="_blank" rel="noreferrer">terminal-bench.com</a> Leaderboard and methodology details for the Terminal Bench benchmark series.</p></li></ul><hr><h2 id="related-technologies" tabindex="-1">Related Technologies <a class="header-anchor" href="#related-technologies" aria-label="Permalink to &quot;Related Technologies&quot;">​</a></h2><ul><li><p><strong>Model Context Protocol (MCP)</strong> — <a href="https://github.com/modelcontextprotocol" target="_blank" rel="noreferrer">github.com/modelcontextprotocol</a> Open protocol for connecting LLMs with external tools and data sources. Ante&#39;s <code>mcp-sdk</code> crate is a Rust implementation of this specification.</p></li><li><p><strong>HuggingFace Candle</strong> — <a href="https://github.com/huggingface/candle" target="_blank" rel="noreferrer">github.com/huggingface/candle</a> Minimalist ML tensor library written in Rust. Used by <code>nanochat-rs</code> for local inference without a Python runtime.</p></li><li><p><strong>Andrej Karpathy&#39;s nanochat</strong> — <a href="https://github.com/karpathy/nanochat" target="_blank" rel="noreferrer">github.com/karpathy/nanochat</a> The original Python-based tiny chat model that inspired Antigma&#39;s Rust port, <code>nanochat-rs</code>.</p></li><li><p><strong>remove-refusals-with-transformers</strong> — <a href="https://github.com/Sumandora/remove-refusals-with-transformers" target="_blank" rel="noreferrer">github.com/Sumandora/remove-refusals-with-transformers</a> Research tool for selectively removing refusal behaviors from transformer models. Served as the basis for Antigma&#39;s abliteration technique and blog post.</p></li></ul><hr><h2 id="key-influences-and-context" tabindex="-1">Key Influences and Context <a class="header-anchor" href="#key-influences-and-context" aria-label="Permalink to &quot;Key Influences and Context&quot;">​</a></h2><ul><li><p><strong>Alan Turing / Bletchley Park</strong> — The Antigma name derives from &quot;anti-Enigma,&quot; referencing the codebreaking effort at Bletchley Park during WWII. Symbolizes the mission to break open black-box AI systems.</p></li><li><p><strong>&quot;The Sovereign Individual&quot;</strong> by James Dale Davidson &amp; Lord William Rees-Mogg (frequently cited alongside Peter Thiel) — Referenced in the Antigma Manifesto as a philosophical anchor for the belief that individuals should control their own computational resources and AI capabilities.</p></li><li><p><strong>Balaji Srinivasan&#39;s Network State</strong> — Concept of cloud-first, digitally-native communities that influence Antigma&#39;s &quot;Sovereign Compute and Network State&quot; vision for decentralized AI infrastructure.</p></li><li><p><strong>Chris Dixon&#39;s &quot;Read, Write, Own&quot; framework</strong> — Articulates the progression from read-only web (Web1) to read-write (Web2) to read-write-own (Web3). Antigma draws on this framing to argue that users should own their AI tooling, not merely rent access to it.</p></li></ul>',20)])])}const d=t(o,[["render",i]]);export{u as __pageData,d as default};
